  phrases: [{ nl: "Hoe laat gaat het museum open?", en: "What time does the museum open?", ipa: "hoo laat khaat hut mew-ZAY-um OH-pun" }, { nl: "Zijn er nog kaartjes?", en: "Are there still tickets?", ipa: "zayn er nokh KAAR-chus" }, { nl: "Is er een rondleiding in het Engels?", en: "Is there a guided tour in English?", ipa: "is er un RONT-lay-ding in hut ENG-uls" }, { nl: "Hoe lang is de rij?", en: "How long is the line?", ipa: "hoo lahng is duh ray" }, { nl: "Is de tentoonstelling gratis?", en: "Is the exhibition free?", ipa: "is duh ten-TOHN-stel-ling KHRAH-tis" }, { nl: "Waar is de ingang?", en: "Where is the entrance?", ipa: "vaar is duh IN-khahng" }],
  grammar: "Dutch often uses gaat open for “opens” and is gesloten for “is closed.” Nog means “still,” as in Zijn er nog kaartjes? meaning “Are there still tickets?” This is useful for popular museums with time slots.",
  practice: ["Ask if there are still tickets.", "Ask whether a guided tour is available in English.", "Ask what time the museum opens.", "Say that an exhibition is free.", "Create a plan to visit one Dutch museum using today’s words."]
