  phrases: [{ nl: "Ik wil graag reserveren.", en: "I would like to make a reservation.", ipa: "ik vil khraakh ray-zer-VAY-run" }, { nl: "Voor hoeveel personen?", en: "For how many people?", ipa: "voor hoo-FAYL per-SOH-nun" }, { nl: "Voor twee personen om zeven uur.", en: "For two people at seven o’clock.", ipa: "voor tway per-SOH-nun om ZAY-vun uur" }, { nl: "Heeft u iets beschikbaar?", en: "Do you have anything available?", ipa: "hayft ew eets buh-SKHEEK-baar" }, { nl: "Kan ik de reservering annuleren?", en: "Can I cancel the reservation?", ipa: "kan ik duh ray-zer-VAY-ring ah-new-LAY-run" }, { nl: "Krijg ik een bevestiging?", en: "Will I get a confirmation?", ipa: "kraykh ik un buh-VES-tuh-khing" }],
