var CONVERSATIONS_EN_NL = [
{ title: "Ordering at a Café", scene: "You are at a small café near a canal in Amsterdam. You want coffee and something sweet, and the barista asks whether you are staying or taking it away.", lines: [{ who: "them", nl: "Goedemorgen, wat mag het zijn?", en: "Good morning, what would you like?" }, { who: "you", nl: "Goedemorgen, mag ik een koffie, alstublieft?", en: "Good morning, may I have a coffee, please?" }, { who: "them", nl: "Natuurlijk, wilt u melk of suiker?", en: "Of course, would you like milk or sugar?" }, { who: "you", nl: "Zonder suiker, maar met melk, graag.", en: "Without sugar, but with milk, please." }, { who: "them", nl: "Wilt u er iets bij eten?", en: "Would you like something to eat with it?" }, { who: "you", nl: "Ja, ik neem een stuk appeltaart.", en: "Yes, I’ll take a piece of apple pie." }, { who: "them", nl: "Voor hier of om mee te nemen?", en: "For here or to go?" }, { who: "you", nl: "Voor hier, alstublieft.", en: "For here, please." }, { who: "them", nl: "Dat is zeven euro vijftig.", en: "That is seven euros fifty." }, { who: "you", nl: "Kan ik met kaart betalen?", en: "Can I pay by card?" }, { who: "them", nl: "Ja, natuurlijk.", en: "Yes, of course." }, { who: "you", nl: "Dank je wel.", en: "Thank you very much." }] },
{ title: "Hotel Check-In", scene: "You arrive at a hotel in Rotterdam after taking the train. You have a reservation and want to ask about breakfast and luggage.", lines: [{ who: "them", nl: "Goedenavond, welkom in ons hotel.", en: "Good evening, welcome to our hotel." }, { who: "you", nl: "Goedenavond, ik heb een reservering.", en: "Good evening, I have a reservation." }, { who: "them", nl: "Op welke naam staat de reservering?", en: "Under what name is the reservation?" }, { who: "you", nl: "Op naam van Cannon.", en: "Under the name Cannon." }, { who: "them", nl: "Mag ik uw paspoort zien?", en: "May I see your passport?" }, { who: "you", nl: "Ja, natuurlijk, hier is mijn paspoort.", en: "Yes, of course, here is my passport." }, { who: "them", nl: "U heeft kamer driehonderdtwee.", en: "You have room three hundred two." }, { who: "you", nl: "Dank u, waar is de lift?", en: "Thank you, where is the elevator?" }, { who: "them", nl: "De lift is links, naast de trap.", en: "The elevator is on the left, next to the stairs." }, { who: "you", nl: "Hoe laat is het ontbijt morgen?", en: "What time is breakfast tomorrow?" }, { who: "them", nl: "Het ontbijt is van zeven tot tien uur.", en: "Breakfast is from seven to ten o’clock." }, { who: "you", nl: "Prima, dank u wel.", en: "Great, thank you very much." }] },
{ title: "Asking for Directions", scene: "You are in Utrecht and want to find the Dom Tower. You stop someone on the street and ask politely for help.", lines: [{ who: "you", nl: "Sorry, kunt u mij helpen?", en: "Sorry, can you help me?" }, { who: "them", nl: "Ja, natuurlijk.", en: "Yes, of course." }, { who: "you", nl: "Waar is de Domtoren?", en: "Where is the Dom Tower?" }, { who: "them", nl: "Ga rechtdoor en sla dan linksaf.", en: "Go straight ahead and then turn left." }, { who: "you", nl: "Is het ver?", en: "Is it far?" }, { who: "them", nl: "Nee, het is ongeveer vijf minuten lopen.", en: "No, it is about five minutes walking." }, { who: "you", nl: "Moet ik over de brug?", en: "Do I have to cross the bridge?" }, { who: "them", nl: "Ja, en daarna ziet u de toren rechts.", en: "Yes, and after that you will see the tower on the right." }, { who: "you", nl: "Bedankt voor de uitleg.", en: "Thanks for the explanation." }, { who: "them", nl: "Geen probleem, fijne dag.", en: "No problem, have a nice day." }, { who: "you", nl: "Dank u, tot ziens.", en: "Thank you, goodbye." }] },
{ title: "At a Restaurant", scene: "You are having dinner in The Hague. You have a reservation and want to ask the server for a recommendation before ordering.", lines: [{ who: "them", nl: "Goedenavond, heeft u gereserveerd?", en: "Good evening, do you have a reservation?" }, { who: "you", nl: "Ja, voor twee personen om zeven uur.", en: "Yes, for two people at seven o’clock." }, { who: "them", nl: "Op welke naam?", en: "Under what name?" }, { who: "you", nl: "Op naam van Cannon.", en: "Under the name Cannon." }, { who: "them", nl: "Prima, volgt u mij maar.", en: "Great, please follow me." }, { who: "you", nl: "Dank u, mogen we de menukaart zien?", en: "Thank you, may we see the menu?" }, { who: "them", nl: "Natuurlijk, hier is de kaart.", en: "Of course, here is the menu." }, { who: "you", nl: "Wat raadt u aan?", en: "What do you recommend?" }, { who: "them", nl: "De vis van de dag is erg lekker.", en: "The fish of the day is very tasty." }, { who: "you", nl: "Dan neem ik de vis, graag.", en: "Then I’ll take the fish, please." }, { who: "them", nl: "Wilt u daar iets bij drinken?", en: "Would you like something to drink with that?" }, { who: "you", nl: "Ja, een glas water, alstublieft.", en: "Yes, a glass of water, please." }] },
{ title: "Buying Train Tickets", scene: "You are at Amsterdam Centraal and want to travel to Delft. You ask a staff member about the ticket and platform.", lines: [{ who: "them", nl: "Goedemiddag, kan ik u helpen?", en: "Good afternoon, can I help you?" }, { who: "you", nl: "Ja, ik wil een kaartje naar Delft.", en: "Yes, I want a ticket to Delft." }, { who: "them", nl: "Wilt u een enkele reis of een retour?", en: "Do you want a one-way ticket or a return ticket?" }, { who: "you", nl: "Een enkele reis, alstublieft.", en: "A one-way ticket, please." }, { who: "them", nl: "Dat is achttien euro.", en: "That is eighteen euros." }, { who: "you", nl: "Kan ik met kaart betalen?", en: "Can I pay by card?" }, { who: "them", nl: "Ja, dat kan.", en: "Yes, you can." }, { who: "you", nl: "Van welk spoor vertrekt de trein?", en: "From which track does the train leave?" }, { who: "them", nl: "De trein vertrekt van spoor vijf.", en: "The train leaves from track five." }, { who: "you", nl: "Moet ik overstappen?", en: "Do I have to transfer?" }, { who: "them", nl: "Ja, u moet overstappen in Leiden.", en: "Yes, you have to transfer in Leiden." }, { who: "you", nl: "Dank u voor de hulp.", en: "Thank you for the help." }] },
{ title: "Shopping at a Market", scene: "You are at a market in Haarlem looking at local cheese and small souvenirs. You want to ask the price and pay by card.", lines: [{ who: "them", nl: "Hallo, kan ik u ergens mee helpen?", en: "Hello, can I help you with anything?" }, { who: "you", nl: "Ja, hoeveel kost deze kaas?", en: "Yes, how much does this cheese cost?" }, { who: "them", nl: "Deze kaas kost zes euro.", en: "This cheese costs six euros." }, { who: "you", nl: "Mag ik een klein stuk proeven?", en: "May I taste a small piece?" }, { who: "them", nl: "Natuurlijk, alstublieft.", en: "Of course, please." }, { who: "you", nl: "Dat is heel lekker.", en: "That is very tasty." }, { who: "them", nl: "Wilt u een stuk meenemen?", en: "Would you like to take a piece?" }, { who: "you", nl: "Ja, dat neem ik.", en: "Yes, I’ll take that." }, { who: "them", nl: "Wilt u ook een tas?", en: "Would you also like a bag?" }, { who: "you", nl: "Ja, graag.", en: "Yes, please." }, { who: "them", nl: "Dat is zes euro vijftig.", en: "That is six euros fifty." }, { who: "you", nl: "Prima, ik betaal met kaart.", en: "Great, I’ll pay by card." }] },
{ title: "At the Pharmacy", scene: "You are in a pharmacy in Amsterdam because you have a sore throat. You need medicine and want to understand how often to take it.", lines: [{ who: "them", nl: "Goedemiddag, waarmee kan ik u helpen?", en: "Good afternoon, how can I help you?" }, { who: "you", nl: "Ik heb keelpijn en ik ben verkouden.", en: "I have a sore throat and I have a cold." }, { who: "them", nl: "Heeft u ook koorts?", en: "Do you also have a fever?" }, { who: "you", nl: "Nee, ik heb geen koorts.", en: "No, I do not have a fever." }, { who: "them", nl: "Dan kunt u deze tabletten nemen.", en: "Then you can take these tablets." }, { who: "you", nl: "Hoe vaak moet ik ze nemen?", en: "How often should I take them?" }, { who: "them", nl: "Drie keer per dag, na het eten.", en: "Three times a day, after eating." }, { who: "you", nl: "Heb ik een recept nodig?", en: "Do I need a prescription?" }, { who: "them", nl: "Nee, dat is niet nodig.", en: "No, that is not necessary." }, { who: "you", nl: "Zijn er bijwerkingen?", en: "Are there side effects?" }, { who: "them", nl: "Misschien wordt u een beetje moe.", en: "Maybe you will become a little tired." }, { who: "you", nl: "Dank u voor de uitleg.", en: "Thank you for the explanation." }] },
{ title: "Small Talk with a Local", scene: "You are sitting at a shared table in a busy café in Utrecht. A local person starts a friendly conversation about your trip.", lines: [{ who: "you", nl: "Hallo, mag ik hier zitten?", en: "Hello, may I sit here?" }, { who: "them", nl: "Ja hoor, geen probleem.", en: "Yes, sure, no problem." }, { who: "you", nl: "Dank je, het is druk vandaag.", en: "Thank you, it is busy today." }, { who: "them", nl: "Ja, het is zaterdag en het weer is mooi.", en: "Yes, it is Saturday and the weather is nice." }, { who: "you", nl: "Ik ben hier op vakantie.", en: "I am here on vacation." }, { who: "them", nl: "Leuk, vind je Utrecht mooi?", en: "Nice, do you think Utrecht is beautiful?" }, { who: "you", nl: "Ja, heel mooi en gezellig.", en: "Yes, very beautiful and pleasant." }, { who: "them", nl: "Waar kom je vandaan?", en: "Where are you from?" }, { who: "you", nl: "Ik kom uit Amerika.", en: "I come from America." }, { who: "them", nl: "Spreek je al lang Nederlands?", en: "Have you been speaking Dutch for a long time?" }, { who: "you", nl: "Nee, ik spreek een beetje Nederlands.", en: "No, I speak a little Dutch." }, { who: "them", nl: "Dat is al heel goed.", en: "That is already very good." }] }
];
